Use MAUI's `Window` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();

        // Subscribe to lifecycle events
        this.Loaded += (s, e) =>
        {
            var window = this.Window;
            if (window is null) return;

            window.Backgrounding += OnBackgrounding;
            window.Resumed += OnResumed;
        };

        // Restore any saved draft on first load
        RestoreDraft();
    }

    private void OnBackgrounding(object? sender, BackgroundingEventArgs e)
    {
        Preferences.Set(DraftKey, DraftEditor.Text ?? string.Empty);
    }

    private void OnResumed(object? sender, EventArgs e)
    {
        RestoreDraft();
    }

    private void RestoreDraft()
    {
        DraftEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

```xml
<!-- NotePage.xaml (relevant snippet) -->
<Editor x:Name="DraftEditor" Placeholder="Start typing..." />
```

**Key points:**

- **`Backgrounding`** fires when the app moves to the background — save here.
- **`Resumed`** fires when the app returns to the foreground — restore here.
- **`Preferences`** is ideal for small strings; for large content use `SecureStorage` or a file via `FileSystem.AppDataDirectory`.
- Call `ClearDraft()` when the user intentionally saves or discards the note so stale drafts don't reappear.
